 1	import React, { FC, useState } from 'react';
 2	
 3	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Overview } from '@openshift-console/dynamic-plugin-sdk';
 6	import { Card, Tab, Tabs, TabTitleText } from '@patternfly/react-core';
 7	
 8	import ClusterTab from './ClusterTab/ClusterTab';
 9	import PreviewFeaturesTab from './PreviewFeaturesTab/PreviewFeaturesTab';
10	import UserTab from './UserTab/UserTab';
11	
12	import './settings-tab.scss';
13	
14	const SettingsTab: FC = () => {
15	  const { t } = useKubevirtTranslation();
16	  const isAdmin = useIsAdmin();
17	  const [activeTab, setActiveTab] = useState<number>(isAdmin ? 0 : 1);
18	
19	  return (
20	    <Overview>
21	      <Card className="settings-tab__card">
22	        <Tabs
23	          activeKey={activeTab}
24	          className="settings-tab__menu"
25	          isVertical
26	          onSelect={(_, activeKey) => setActiveTab(+activeKey)}
27	        >
28	          {isAdmin && (
29	            <Tab eventKey={0} title={<TabTitleText>{t('Cluster')}</TabTitleText>}>
30	              <div className="settings-tab__content">
31	                <ClusterTab />
32	              </div>
33	            </Tab>
34	          )}
35	          <Tab eventKey={1} title={<TabTitleText>{t('User')}</TabTitleText>}>
36	            <div className="settings-tab__content">
37	              <UserTab />
38	            </div>
39	          </Tab>
40	          <Tab eventKey={2} title={<TabTitleText>{t('Preview features')}</TabTitleText>}>
41	            <div className="settings-tab__content">
42	              <PreviewFeaturesTab />
43	            </div>
44	          </Tab>
45	        </Tabs>
46	      </Card>
47	    </Overview>
48	  );
49	};
50	
51	export default SettingsTab;

